const input = $input.first().json;
const action = input.action || 'search_repos';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.github-api&cred_key=eq.github_pat&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'GitHub PAT not configured. Use add_credential to set it up.' } }];
}

const token = creds[0].cred_value;
const ghHeaders = {
  'Authorization': 'Bearer ' + token,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28'
};

function formatNumber(n) {
  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';
  return String(n);
}

function repoUrl(owner, repo) {
  return 'https://api.github.com/repos/' + encodeURIComponent(owner) + '/' + encodeURIComponent(repo);
}

// === search_repos ===
if (action === 'search_repos') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const sort = input.sort || 'stars';

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/search/repositories?q=' + encodeURIComponent(query) + '&sort=' + sort + '&per_page=5',
      headers: ghHeaders
    });

    if (!data.items || data.items.length === 0) {
      return [{ json: { error: 'No repositories found for "' + query + '".' } }];
    }

    let result = 'GitHub repos for "' + query + '" (' + data.total_count + ' total):\n\n';
    for (const r of data.items) {
      result += '**' + r.full_name + '**';
      result += ' — ' + formatNumber(r.stargazers_count) + ' stars, ' + formatNumber(r.forks_count) + ' forks\n';
      if (r.description) result += r.description.substring(0, 150) + '\n';
      if (r.language) result += 'Language: ' + r.language + '\n';
      result += r.html_url + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'GitHub search failed: ' + err.message } }];
  }

// === get_repo_info ===
} else if (action === 'get_repo_info') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];

  try {
    const data = await helpers.httpRequest({ method: 'GET', url: repoUrl(owner, repo), headers: ghHeaders });

    let result = '**' + data.full_name + '**\n';
    if (data.description) result += data.description + '\n';
    result += '\n';
    result += 'Stars: ' + formatNumber(data.stargazers_count) + '\n';
    result += 'Forks: ' + formatNumber(data.forks_count) + '\n';
    result += 'Open Issues: ' + data.open_issues_count + '\n';
    if (data.language) result += 'Language: ' + data.language + '\n';
    if (data.license && data.license.spdx_id) result += 'License: ' + data.license.spdx_id + '\n';
    result += 'Created: ' + data.created_at.split('T')[0] + '\n';
    result += 'Last Push: ' + data.pushed_at.split('T')[0] + '\n';
    if (data.topics && data.topics.length > 0) result += 'Topics: ' + data.topics.join(', ') + '\n';
    result += 'Default Branch: ' + data.default_branch + '\n';
    result += 'URL: ' + data.html_url + '\n';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get repo info: ' + err.message } }];
  }

// === list_issues ===
} else if (action === 'list_issues') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];
  const state = input.state || 'open';

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: repoUrl(owner, repo) + '/issues?state=' + state + '&per_page=10',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No ' + state + ' issues found in ' + owner + '/' + repo + '.' } }];
    }

    const issues = data.filter(i => !i.pull_request);
    if (issues.length === 0) {
      return [{ json: { result: 'No ' + state + ' issues found in ' + owner + '/' + repo + ' (only pull requests).' } }];
    }

    let result = state.charAt(0).toUpperCase() + state.slice(1) + ' issues in ' + owner + '/' + repo + ':\n\n';
    for (const i of issues) {
      result += '#' + i.number + ' — **' + i.title + '**\n';
      if (i.labels && i.labels.length > 0) result += '  Labels: ' + i.labels.map(l => l.name).join(', ') + '\n';
      result += '  Created: ' + i.created_at.split('T')[0];
      if (i.assignee) result += ' | Assignee: ' + i.assignee.login;
      result += '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list issues: ' + err.message } }];
  }

// === create_issue ===
} else if (action === 'create_issue') {
  const owner = input.owner;
  const repo = input.repo;
  const title = input.title;
  if (!owner || !repo || !title) return [{ json: { error: 'Parameters "owner", "repo", and "title" are required.' } }];

  try {
    const body = { title };
    if (input.body) body.body = input.body;
    if (input.labels) body.labels = input.labels.split(',').map(l => l.trim());

    const data = await helpers.httpRequest({
      method: 'POST',
      url: repoUrl(owner, repo) + '/issues',
      headers: { ...ghHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    return [{ json: { result: 'Issue created: #' + data.number + ' — ' + data.title + '\n' + data.html_url } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create issue: ' + err.message } }];
  }

// === list_pull_requests ===
} else if (action === 'list_pull_requests') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];
  const state = input.state || 'open';

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: repoUrl(owner, repo) + '/pulls?state=' + state + '&per_page=10',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No ' + state + ' pull requests in ' + owner + '/' + repo + '.' } }];
    }

    let result = state.charAt(0).toUpperCase() + state.slice(1) + ' PRs in ' + owner + '/' + repo + ':\n\n';
    for (const pr of data) {
      result += '#' + pr.number + ' — **' + pr.title + '**\n';
      result += '  ' + pr.user.login + ' | ' + pr.head.ref + ' -> ' + pr.base.ref + '\n';
      if (pr.draft) result += '  [DRAFT]\n';
      result += '  Created: ' + pr.created_at.split('T')[0];
      if (pr.merged_at) result += ' | Merged: ' + pr.merged_at.split('T')[0];
      result += '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list PRs: ' + err.message } }];
  }

// === get_pull_request ===
} else if (action === 'get_pull_request') {
  const owner = input.owner;
  const repo = input.repo;
  const prNumber = input.pr_number;
  if (!owner || !repo || !prNumber) return [{ json: { error: 'Parameters "owner", "repo", and "pr_number" are required.' } }];

  try {
    const pr = await helpers.httpRequest({
      method: 'GET',
      url: repoUrl(owner, repo) + '/pulls/' + prNumber,
      headers: ghHeaders
    });

    let result = '#' + pr.number + ' — **' + pr.title + '**\n';
    result += 'Author: ' + pr.user.login + '\n';
    result += 'State: ' + pr.state;
    if (pr.draft) result += ' (draft)';
    if (pr.merged) result += ' (merged)';
    result += '\n';
    result += 'Branch: ' + pr.head.ref + ' -> ' + pr.base.ref + '\n';
    result += 'Changed Files: ' + pr.changed_files + ' | +' + pr.additions + ' -' + pr.deletions + '\n';
    result += 'Commits: ' + pr.commits + '\n';
    if (pr.body) result += '\nDescription:\n' + pr.body.substring(0, 500) + (pr.body.length > 500 ? '...' : '') + '\n';
    result += '\nCreated: ' + pr.created_at.split('T')[0];
    if (pr.merged_at) result += ' | Merged: ' + pr.merged_at.split('T')[0];
    result += '\n' + pr.html_url + '\n';

    // Get review status
    try {
      const reviews = await helpers.httpRequest({
        method: 'GET',
        url: repoUrl(owner, repo) + '/pulls/' + prNumber + '/reviews',
        headers: ghHeaders
      });
      if (reviews && reviews.length > 0) {
        const latest = {};
        for (const r of reviews) {
          if (r.state !== 'COMMENTED') latest[r.user.login] = r.state;
        }
        const reviewEntries = Object.entries(latest);
        if (reviewEntries.length > 0) {
          result += '\nReviews:\n';
          for (const [user, state] of reviewEntries) {
            result += '  ' + user + ': ' + state + '\n';
          }
        }
      }
    } catch(e) { /* non-critical */ }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get PR: ' + err.message } }];
  }

// === get_file_content ===
} else if (action === 'get_file_content') {
  const owner = input.owner;
  const repo = input.repo;
  const path = input.path;
  if (!owner || !repo || !path) return [{ json: { error: 'Parameters "owner", "repo", and "path" are required.' } }];
  const ref = input.ref || '';

  try {
    let url = repoUrl(owner, repo) + '/contents/' + encodeURIComponent(path);
    if (ref) url += '?ref=' + encodeURIComponent(ref);

    const data = await helpers.httpRequest({ method: 'GET', url, headers: ghHeaders });

    if (Array.isArray(data)) {
      // It's a directory
      let result = 'Directory: ' + path + '\n\n';
      for (const item of data) {
        result += (item.type === 'dir' ? '[dir]  ' : '[file] ') + item.name + '\n';
      }
      return [{ json: { result } }];
    }

    if (data.type === 'file' && data.content) {
      const content = Buffer.from(data.content, 'base64').toString('utf-8');
      const sizeKB = (data.size / 1024).toFixed(1);
      let result = 'File: ' + data.path + ' (' + sizeKB + ' KB)\n';
      // Truncate very large files
      if (content.length > 5000) {
        result += '\n' + content.substring(0, 5000) + '\n\n... (truncated, ' + content.length + ' chars total)';
      } else {
        result += '\n' + content;
      }
      return [{ json: { result } }];
    }

    return [{ json: { error: 'Unsupported content type or file too large for API.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get file: ' + err.message } }];
  }

// === search_code ===
} else if (action === 'search_code') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];

  try {
    let q = query;
    if (input.owner && input.repo) q += ' repo:' + input.owner + '/' + input.repo;
    else if (input.owner) q += ' user:' + input.owner;

    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/search/code?q=' + encodeURIComponent(q) + '&per_page=10',
      headers: ghHeaders
    });

    if (!data.items || data.items.length === 0) {
      return [{ json: { error: 'No code found matching "' + query + '".' } }];
    }

    let result = 'Code search for "' + query + '" (' + data.total_count + ' total):\n\n';
    for (const item of data.items.slice(0, 10)) {
      result += '**' + item.repository.full_name + '** / ' + item.path + '\n';
      result += '  ' + item.html_url + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Code search failed: ' + err.message } }];
  }

// === list_releases ===
} else if (action === 'list_releases') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: repoUrl(owner, repo) + '/releases?per_page=5',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No releases found in ' + owner + '/' + repo + '.' } }];
    }

    let result = 'Releases in ' + owner + '/' + repo + ':\n\n';
    for (const r of data) {
      result += '**' + r.tag_name + '**';
      if (r.name && r.name !== r.tag_name) result += ' — ' + r.name;
      result += '\n';
      result += '  Published: ' + r.published_at.split('T')[0];
      if (r.prerelease) result += ' [pre-release]';
      if (r.draft) result += ' [draft]';
      result += '\n';
      if (r.body) result += '  ' + r.body.substring(0, 200) + (r.body.length > 200 ? '...' : '') + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list releases: ' + err.message } }];
  }

// === list_notifications ===
} else if (action === 'list_notifications') {
  try {
    const all = input.all === 'true' || input.all === true ? 'true' : 'false';
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/notifications?all=' + all + '&per_page=15',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No notifications.' } }];
    }

    let result = 'GitHub Notifications (' + data.length + '):\n\n';
    for (const n of data) {
      result += '- [' + n.reason + '] **' + n.subject.title + '**\n';
      result += '  ' + n.repository.full_name + ' | ' + n.subject.type + '\n';
      result += '  Updated: ' + n.updated_at.split('T')[0] + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list notifications: ' + err.message } }];
  }

// === list_starred ===
} else if (action === 'list_starred') {
  try {
    const sort = input.sort || 'created';
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/user/starred?sort=' + sort + '&per_page=10',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No starred repositories.' } }];
    }

    let result = 'Your starred repos:\n\n';
    for (const r of data) {
      result += '**' + r.full_name + '**';
      result += ' — ' + formatNumber(r.stargazers_count) + ' stars\n';
      if (r.description) result += '  ' + r.description.substring(0, 120) + '\n';
      if (r.language) result += '  Language: ' + r.language + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list starred repos: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: search_repos, get_repo_info, list_issues, create_issue, list_pull_requests, get_pull_request, get_file_content, search_code, list_releases, list_notifications, list_starred.' } }];
}
